// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Create the VM once and reuse it for all items
	vm := otto.New()

	// Set a timeout to prevent infinite loops or long-running scripts.
	// otto supports interrupting via a panic that we catch.
	const scriptTimeout = 5 * time.Second

	for _, currentItem := range items {
		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", currentItem)
		if err != nil {
			return nil, err
		}

		// Set up the interrupt channel to enforce a timeout
		vm.Interrupt = make(chan func(), 1)

		// Start a timer that will interrupt the VM if the script runs too long
		timer := time.AfterFunc(scriptTimeout, func() {
			vm.Interrupt <- func() {
				panic(fmt.Errorf("script execution timed out after %s", scriptTimeout))
			}
		})

		// Run the condition script, catching any panic from the interrupt
		value, err := func() (val otto.Value, runErr error) {
			defer func() {
				if r := recover(); r != nil {
					runErr = fmt.Errorf("script execution error: %v", r)
				}
			}()
			return vm.Run(conditionScript)
		}()

		// Stop the timer since execution completed (or panicked)
		timer.Stop()

		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, currentItem)
		}
	}

	return result, nil
}

func main() {
	items := []map[string]interface{}{
		{"id": 1, "active": true},
		{"id": 2, "active": false},
		{"id": 3, "active": true},
	}

	script := "item.active == true"

	filtered, err := FilterItems(script, items)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Println("Filtered items:")
	for _, item := range filtered {
		fmt.Printf("  %v\n", item)
	}
}

