// errScriptTimeout is a sentinel error for script execution timeout.
var errScriptTimeout = fmt.Errorf("script execution timed out")

// runWithTimeout executes a script in the given Otto VM with a timeout.
// If the script does not complete within the given duration, the VM is interrupted
// and an error is returned.
func runWithTimeout(vm *otto.Otto, script string, timeout time.Duration) (otto.Value, error) {
	type runResult struct {
		value otto.Value
		err   error
	}

	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	// Set up the interrupt: otto uses a panic-based interrupt mechanism.
	// We start a goroutine that will call vm.Interrupt after the timeout.
	done := make(chan struct{})
	defer close(done)

	go func() {
		select {
		case <-ctx.Done():
			vm.Interrupt <- func() {
				panic(errScriptTimeout)
			}
		case <-done:
			// Script completed before timeout; nothing to do.
		}
	}()

	resultCh := make(chan runResult, 1)

	go func() {
		defer func() {
			if r := recover(); r != nil {
				if r == errScriptTimeout {
					resultCh <- runResult{value: otto.UndefinedValue(), err: errScriptTimeout}
				} else {
					resultCh <- runResult{value: otto.UndefinedValue(), err: fmt.Errorf("script panic: %v", r)}
				}
			}
		}()

		value, err := vm.Run(script)
		resultCh <- runResult{value: value, err: err}
	}()

	res := <-resultCh
	return res.value, res.err
}

